              <PaymentMethodDisplay {...paymentMethod} showExpiration={false} />
            </div>
            <Button onClick={onClickNew}>Change payment method</Button>
          </div>
          <FormMaskedInputControl
            autoComplete="cc-exp"
            data-analytics-ignore
            isRequired
            label="Expiration date"
            name="expDate"
            type="expiry"
          />
          {additionalAction}
        </div>
      </FormGroup>
      <FormGroup title="Billing address">
        <FormAddressControl />
      </FormGroup>
    </>
